import numpy as np, sys, re

# ---- tokenizer from vocab.bpe only ----
def bytes_to_unicode():
    bs=list(range(33,127))+list(range(161,173))+list(range(174,256))
    cs=bs[:]; n=0
    for b in range(256):
        if b not in bs:
            bs.append(b); cs.append(256+n); n+=1
    return {b:chr(c) for b,c in zip(bs,cs)}
b2u=bytes_to_unicode(); u2b={v:k for k,v in b2u.items()}
merges=[]
for i,line in enumerate(open('vocab.bpe',encoding='utf-8')):
    if i==0: continue
    line=line.rstrip('\n')
    if not line: continue
    a,b=line.split(' '); merges.append((a,b))
# build vocab id map
vocab={}
# base 256: order of bs
bs=list(range(33,127))+list(range(161,173))+list(range(174,256))
for b in range(256):
    if b not in bs: bs.append(b)
for i,b in enumerate(bs):
    vocab[b2u[b]]=i
for j,(a,b) in enumerate(merges):
    vocab[a+b]=256+j
vocab['<|endoftext|>']=50256
enc=vocab
dec={v:k for k,v in vocab.items()}
bpe_ranks={m:i for i,m in enumerate(merges)}
pat=re.compile(r"""'s|'t|'re|'ve|'m|'ll|'d| ?\w+| ?[^\s\w]+|\s+(?!\S)|\s+""")
def get_pairs(word):
    return set(zip(word[:-1],word[1:]))
def bpe(token):
    word=tuple(token); 
    if len(word)<2: return list(word)
    while True:
        pairs=get_pairs(word)
        mn=min(pairs,key=lambda p:bpe_ranks.get(p,1e9))
        if mn not in bpe_ranks: break
        a,b=mn; nw=[]; i=0
        while i<len(word):
            if i<len(word)-1 and word[i]==a and word[i+1]==b:
                nw.append(a+b); i+=2
            else: nw.append(word[i]); i+=1
        word=tuple(nw)
        if len(word)==1: break
    return list(word)
def encode(text):
    ids=[]
    for tok in re.findall(pat,text):
        tok=''.join(b2u[c] for c in tok.encode('utf-8'))
        for p in bpe(tok): ids.append(enc[p])
    return ids
def decode(ids):
    s=''.join(dec[i] for i in ids)
    return bytearray(u2b[c] for c in s).decode('utf-8',errors='replace')

# ---- weights natural order ----
f=np.memmap('gpt2-124M.ckpt',dtype='<f4',mode='r')
V,C,L,H=50257,768,12,12
off=[0]
def take(*sh):
    n=int(np.prod(sh)); a=np.array(f[off[0]:off[0]+n]).reshape(sh); off[0]+=n; return a
wte=take(V,C); wpe=take(1024,C)
layers=[]
for _ in range(L):
    d={}
    d['ln1g']=take(C); d['ln1b']=take(C)
    d['aw']=take(C,3*C); d['ab']=take(3*C)
    d['pw']=take(C,C); d['pb']=take(C)
    d['ln2g']=take(C); d['ln2b']=take(C)
    d['fw']=take(C,4*C); d['fb']=take(4*C)
    d['mw']=take(4*C,C); d['mb']=take(C)
    layers.append(d)
lnfg=take(C); lnfb=take(C)
print("consumed",off[0],"of",f.size)

def ln(x,g,b):
    m=x.mean(-1,keepdims=True); v=x.var(-1,keepdims=True)
    return (x-m)/np.sqrt(v+1e-5)*g+b
def gelu(x):
    return 0.5*x*(1+np.tanh(np.sqrt(2/np.pi)*(x+0.044715*x**3)))
def softmax(x):
    x=x-x.max(-1,keepdims=True); e=np.exp(x); return e/e.sum(-1,keepdims=True)
def forward(ids):
    x=wte[ids]+wpe[:len(ids)]
    for d in layers:
        h=ln(x,d['ln1g'],d['ln1b'])
        qkv=h@d['aw']+d['ab']
        q,k,v=np.split(qkv,3,axis=-1)
        hs=C//H
        def sh(t): return t.reshape(len(ids),H,hs).transpose(1,0,2)
        q,k,v=sh(q),sh(k),sh(v)
        att=q@k.transpose(0,2,1)/np.sqrt(hs)
        mask=np.triu(np.ones((len(ids),len(ids)))*-1e10,1)
        att=softmax(att+mask)
        o=(att@v).transpose(1,0,2).reshape(len(ids),C)
        x=x+o@d['pw']+d['pb']
        h=ln(x,d['ln2g'],d['ln2b'])
        x=x+gelu(h@d['fw']+d['fb'])@d['mw']+d['mb']
    x=ln(x,lnfg,lnfb)
    return x@wte.T

prompt=sys.argv[1] if len(sys.argv)>1 else "Alan Turing theorized that computers would one day become"
ids=encode(prompt)
print("ids",ids)
for _ in range(20):
    logits=forward(ids)
    nid=int(logits[-1].argmax())
    ids.append(nid)
print("OUT:",repr(decode(ids)))
